import{_ as a,o as t,c as n,a0 as i}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"基础技巧","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"数独文章/基础技巧.md","filePath":"数独文章/基础技巧.md"}'),r={name:"数独文章/基础技巧.md"};function o(d,e,l,p,_,s){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="基础技巧" tabindex="-1">基础技巧 <a class="header-anchor" href="#基础技巧" aria-label="Permalink to &quot;基础技巧&quot;">​</a></h1><h2 id="排除法-摒除法" tabindex="-1">排除法（摒除法） <a class="header-anchor" href="#排除法-摒除法" aria-label="Permalink to &quot;排除法（摒除法）&quot;">​</a></h2><p>摒除法：用数字去找单元内唯一可填空格，称为摒除法，数字可填唯一空格称为排除法 (Hidden Single)。</p><p>根据不同的作用范围，摒余解可分为下述三种：</p><p>数字可填唯一空格在「宫」单元称为宫排除（Hidden Single in Box），也称宫摒除法。</p><p>数字可填唯一空格在「行」单元称为行排除法（Hidden Single in Row），也称行摒除法。</p><p>数字可填唯一空格在「列」单元称为列排除法（Hidden Single in Column），也称列摒除法。</p><h2 id="唯一余数法" tabindex="-1">唯一余数法 <a class="header-anchor" href="#唯一余数法" aria-label="Permalink to &quot;唯一余数法&quot;">​</a></h2><p>唯一余数法：用格位去找唯一可填数字，称为余数法，格位唯一可填数字称为唯余解（Naked Single）。</p><p>余数法是删减等位群格位（Peer）已出现的数字的方法，每一格位的等位群格位有20个。</p>',10)])])}const m=a(r,[["render",o]]);export{h as __pageData,m as default};
